const t={boardTopology:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Observa cómo se conectan las placas de control de tu impresora: el host (SBC) y cada MCU con el que se comunica, con el tipo de cada conexión y una estimación de la placa o chip lo más precisa posible, leída en vivo desde la configuración."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Ayuda"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Acerca de la topología de placas"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Cerrar"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Cómo interpretarlo"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"El host (tu SBC, por ejemplo una Raspberry Pi o CB1) se sitúa arriba."}},{t:0,b:{t:2,i:[{t:3}],s:"Cada tarjeta de MCU muestra cómo se conecta (USB / CAN bus / UART) y su chip."}},{t:0,b:{t:2,i:[{t:3}],s:"Aparece una estimación de la placa cuando el identificador de conexión coincide con una placa conocida."}}],topics:{mcus:{title:{t:0,b:{t:2,i:[{t:3}],s:"MCUs"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un MCU es una placa microcontroladora que controla motores, calentadores y sensores. Una impresora tiene al menos uno (la placa base); muchas añaden una placa de cabezal y a veces una placa de sonda o de LED. Este panel lista cada sección `[mcu]` que tiene Klipper."}}},connections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Tipos de conexión"}},body:{t:0,b:{t:2,i:[{t:3}],s:"USB — un enlace serie sobre USB (la conexión habitual de la placa base). CAN bus — un bus compartido de dos hilos, común para placas de cabezal. UART — un enlace serie directo por GPIO. El tipo se infiere de los ajustes `serial` / `canbus_uuid` de cada MCU."}}},detection:{title:{t:0,b:{t:2,i:[{t:3}],s:"Cómo funciona la detección"}},body:{t:0,b:{t:2,i:[{t:3}],s:"El chip y la placa se deducen comparando el identificador de conexión (la ruta serie o el UUID de CAN) con una tabla de patrones, más una huella del mapa de pines que usa tu configuración. Una propuesta de placa muestra una confianza de coincidencia; si nada coincide, el chip/placa aparece como «desconocido», pero la conexión se sigue mostrando."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glosario"}},body:{t:0,b:{static:"",t:2,i:[]}}},override:{title:{t:0,b:{t:2,i:[{t:3}],s:"Confirmar o cambiar una placa"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un id serie suele revelar solo el chip, así que la placa propuesta puede faltar o ser incorrecta. Usa «Confirmar esta placa» para fijar una propuesta correcta, o «Cambiar placa…» / «Elegir placa…» para escoger la correcta del catálogo. Tu elección se guarda en el host y se reutiliza en cada lectura; «Borrar» vuelve a la propuesta automática."}}},views:{title:{t:0,b:{t:2,i:[{t:3}],s:"Vista física vs. lógica"}},body:{t:0,b:{t:2,i:[{t:3}],s:"El mapa dibuja las mismas placas de dos formas. FÍSICA muestra cómo está construida la máquina: un SBC integrado se dibuja dentro de la placa base en la que viene, los cabezales CAN cuelgan de un bus troncal compartido y las placas USB/UART son unidades separadas. LÓGICA muestra cómo lo ve Klipper: el host arriba y cada MCU como hijo a través de su enlace serie. Cambia con el interruptor Física/Lógica."}}}},glossary:{mcu:{term:{t:0,b:{t:2,i:[{t:3}],s:"MCU"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Unidad microcontroladora — una placa de control que ejecuta el firmware de Klipper (placa base, cabezal, etc.)."}}},canbus:{term:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Un bus compartido de dos hilos que enlaza placas mediante un UUID único — popular para el cableado del cabezal."}}},host:{term:{t:0,b:{t:2,i:[{t:3}],s:"Host / SBC"}},def:{t:0,b:{t:2,i:[{t:3}],s:"El ordenador de placa única (Pi, CB1, …) que ejecuta Klipper y se comunica con los MCUs."}}}}},host:{label:{t:0,b:{t:2,i:[{t:3}],s:"Host"}},role:{t:0,b:{t:2,i:[{t:3}],s:"Ordenador de placa única — ejecuta Klipper"}}},mcu:{chip:{t:0,b:{t:2,i:[{t:3}],s:"Chip"}},board:{t:0,b:{t:2,i:[{t:3}],s:"Placa"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"desconocido"}},identifier:{t:0,b:{t:2,i:[{t:3}],s:"Identificador"}},confidence:{t:0,b:{t:2,i:[{t:4,k:"pct"},{t:3,v:"% de coincidencia"}]}},viewBoard:{t:0,b:{t:2,i:[{t:3}],s:"Ver detalles de la placa"}},hideBoard:{t:0,b:{t:2,i:[{t:3}],s:"Ocultar detalles"}}},conn:{canbus:{t:0,b:{t:2,i:[{t:3}],s:"CAN bus"}},usb:{t:0,b:{t:2,i:[{t:3}],s:"USB"}},uart:{t:0,b:{t:2,i:[{t:3}],s:"UART"}},unknown:{t:0,b:{t:2,i:[{t:3}],s:"desconocido"}},via:{t:0,b:{t:2,i:[{t:3,v:"vía "},{t:4,k:"type"}]}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" MCUs"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Leyendo la topología…"}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"No se pudo conectar con la impresora."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"No se encontraron MCUs en la configuración."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Reintentar"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"Actualizar"}}},board:{suggested:{t:0,b:{t:2,i:[{t:3}],s:"sugerido"}},ports:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" puertos"}]}},specsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Especificaciones"}},portsTitle:{t:0,b:{t:2,i:[{t:3}],s:"Puertos"}},none:{t:0,b:{t:2,i:[{t:3}],s:"Aún no hay detalles de catálogo para esta placa."}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Cargando placa…"}},links:{title:{t:0,b:{t:2,i:[{t:3}],s:"Enlaces"}},product:{t:0,b:{t:2,i:[{t:3}],s:"Producto"}},repo:{t:0,b:{t:2,i:[{t:3}],s:"Repo"}},wiki:{t:0,b:{t:2,i:[{t:3}],s:"Wiki"}},pinout:{t:0,b:{t:2,i:[{t:3}],s:"Pinout"}},schematic:{t:0,b:{t:2,i:[{t:3}],s:"Esquema"}},datasheet:{t:0,b:{t:2,i:[{t:3}],s:"Hoja de datos"}},image:{t:0,b:{t:2,i:[{t:3}],s:"Foto"}}},noMatch:{t:0,b:{t:2,i:[{t:3}],s:"Ninguna placa coincidente aún — confirma o elige una abajo."}}},components:{title:{t:0,b:{t:2,i:[{t:3}],s:"Componentes"}},motor:{t:0,b:{t:2,i:[{t:3}],s:"Motores"}},driver:{t:0,b:{t:2,i:[{t:3}],s:"Drivers"}},heater:{t:0,b:{t:2,i:[{t:3}],s:"Calentadores"}},fan:{t:0,b:{t:2,i:[{t:3}],s:"Ventiladores"}},sensor:{t:0,b:{t:2,i:[{t:3}],s:"Sensores"}}},sync:{synced:{t:0,b:{t:2,i:[{t:3}],s:"Firmware sincronizado"}},outOfSync:{t:0,b:{t:2,i:[{t:3}],s:"Firmware DESINCRONIZADO"}}},override:{confirmed:{t:0,b:{t:2,i:[{t:3}],s:"Confirmado por ti"}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"Confirmar esta placa"}},change:{t:0,b:{t:2,i:[{t:3}],s:"Cambiar placa…"}},set:{t:0,b:{t:2,i:[{t:3}],s:"Elegir placa…"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"Borrar"}},pickPlaceholder:{t:0,b:{t:2,i:[{t:3}],s:"Buscar en el catálogo de placas…"}},hint:{t:0,b:{t:2,i:[{t:3}],s:"Tu elección se guarda en el host y se usa para este MCU a partir de ahora."}}},graph:{viewLabel:{t:0,b:{t:2,i:[{t:3}],s:"Vista del diagrama"}},view:{physical:{t:0,b:{t:2,i:[{t:3}],s:"Física"}},logical:{t:0,b:{t:2,i:[{t:3}],s:"Lógica"}}},integrated:{t:0,b:{t:2,i:[{t:3}],s:"SBC integrado"}},integratedNote:{t:0,b:{t:2,i:[{t:3,v:"El SBC anfitrión está integrado en la placa base "},{t:4,k:"board"},{t:3,v:"."}]}},selectPrompt:{t:0,b:{t:2,i:[{t:3}],s:"Selecciona una placa o un MCU en el mapa para inspeccionarlo."}},aria:{t:0,b:{t:2,i:[{t:3,v:"Mapa de la máquina: el host y "},{t:4,k:"n"},{t:3,v:" MCU"}]}},vitals:{freq:{t:0,b:{t:2,i:[{t:4,k:"mhz"},{t:3,v:" MHz"}]}},retx:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" retransmisiones"}]}},load:{t:0,b:{t:2,i:[{t:4,k:"pct"},{t:3,v:"% de carga"}]}}},health:{title:{t:0,b:{t:2,i:[{t:3}],s:"Salud del enlace"}},ok:{t:0,b:{t:2,i:[{t:3}],s:"saludable"}},warn:{t:0,b:{t:2,i:[{t:3}],s:"degradado"}},out:{t:0,b:{t:2,i:[{t:3}],s:"firmware desincronizado"}}}},pinAtlas:{tab:{details:{t:0,b:{t:2,i:[{t:3}],s:"Detalles"}},atlas:{t:0,b:{t:2,i:[{t:3}],s:"Atlas de pines"}}},summary:{t:0,b:{t:2,i:[{t:4,k:"used"},{t:3,v:"/"},{t:4,k:"total"},{t:3,v:" pines usados · "},{t:4,k:"free"},{t:3,v:" libres"}]}},loading:{t:0,b:{t:2,i:[{t:3}],s:"Leyendo el mapa de pines…"}},failed:{t:0,b:{t:2,i:[{t:3}],s:"No se pudo leer el mapa de pines."}},unavailable:{t:0,b:{t:2,i:[{t:3}],s:"Aún no hay mapa de pines para esta placa."}},search:{t:0,b:{t:2,i:[{t:3}],s:"Buscar pines, señales, secciones…"}},freeOnly:{t:0,b:{t:2,i:[{t:3}],s:"Solo libres"}},noMatch:{t:0,b:{t:2,i:[{t:3}],s:"Ningún pin coincide."}},other:{t:0,b:{t:2,i:[{t:3}],s:"Otros"}},conflict:{t:0,b:{t:2,i:[{t:3}],s:"Conflicto de pines"}},caveat:{t:0,b:{t:2,i:[{t:3}],s:"Advertencia de cableado"}}},snapshot:{save:{t:0,b:{t:2,i:[{t:3}],s:"Guardar instantánea"}},copy:{t:0,b:{t:2,i:[{t:3}],s:"Copiar resumen"}},copied:{t:0,b:{t:2,i:[{t:3}],s:"¡Copiado!"}},none:{t:0,b:{t:2,i:[{t:3}],s:"No hay línea base guardada — guarda una instantánea para detectar cambios futuros."}},unchanged:{t:0,b:{t:2,i:[{t:3}],s:"Sin cambios de hardware desde la instantánea"}},changed:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" cambio(s) desde la instantánea"}]}},summaryTitle:{t:0,b:{t:2,i:[{t:3}],s:"FilaMind — mapa de la máquina"}},change:{added:{t:0,b:{t:2,i:[{t:3,v:"Se añadió el MCU «"},{t:4,k:"mcu"},{t:3,v:"»"}]}},removed:{t:0,b:{t:2,i:[{t:3,v:"Se quitó el MCU «"},{t:4,k:"mcu"},{t:3,v:"»"}]}},board_changed:{t:0,b:{t:2,i:[{t:3,v:"La placa de «"},{t:4,k:"mcu"},{t:3,v:"» cambió: "},{t:4,k:"before"},{t:3,v:" → "},{t:4,k:"after"}]}},connection_changed:{t:0,b:{t:2,i:[{t:3,v:"La conexión de «"},{t:4,k:"mcu"},{t:3,v:"» cambió: "},{t:4,k:"before"},{t:3,v:" → "},{t:4,k:"after"}]}},chip_changed:{t:0,b:{t:2,i:[{t:3,v:"El chip de «"},{t:4,k:"mcu"},{t:3,v:"» cambió: "},{t:4,k:"before"},{t:3,v:" → "},{t:4,k:"after"}]}},components_changed:{t:0,b:{t:2,i:[{t:3,v:"El número de componentes de «"},{t:4,k:"mcu"},{t:3,v:"» cambió: "},{t:4,k:"before"},{t:3,v:" → "},{t:4,k:"after"}]}}},noCompare:{t:0,b:{t:2,i:[{t:3}],s:"No se pudo comparar — la impresora no responde."}},summaryHost:{t:0,b:{t:2,i:[{t:3,v:"Host: "},{t:4,k:"name"}]}},summaryIntegrated:{t:0,b:{t:2,i:[{t:3,v:"SBC integrado en "},{t:4,k:"board"}]}},summaryMcu:{t:0,b:{t:2,i:[{t:3,v:"MCU "},{t:4,k:"name"}]}},summaryBoard:{t:0,b:{t:2,i:[{t:3,v:"placa "},{t:4,k:"board"}]}},summaryComponents:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" componentes"}]}}},jump:{section:{t:0,b:{t:2,i:[{t:3}],s:"Abrir esta sección en el Editor de configuración"}},drivers:{t:0,b:{t:2,i:[{t:3}],s:"Abrir en Motor Drivers"}},firmware:{t:0,b:{t:2,i:[{t:3}],s:"Abrir el Gestor de firmware"}}}}};export{t as default};
